INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L083$$, 2026, $$The Combat Rescue Helicopter (HH-60W) program will replace the aging HH-60G. The HH-60W will be capable of employment day or night, in adverse weather, and across the full spectrum of threats to include
 chemical, biological, radiological, and nuclear. On-board defensive capabilities will permit the HH-60W system to operate with less risk than legacy systems in an increased threat environment. An in-flight air
 refueling capability will provide an airborne alert capability and extend its combat mission range. The HH-60W system is capable of conducting combat search and rescue airborne mission commander duties.
 The aircraft will be self-supporting to the maximum extent practical. The HH-60W system may also conduct other collateral missions inherent in its capabilities to conduct Personnel Recovery, such as non-
 conventional assisted recovery, non-conventional evacuation operations, defense support to civil authorities, civil search and rescue, international aid, emergency aeromedical evacuation, disaster/humanitarian
 relief, counter-drug activities, support for National Aeronautics and Space Administration flight operations, and insertion/extraction of combat forces.

 Funding for this exhibit contained in PE 0207229F.

 Future efforts may include Directional Infrared Counter Measure capability, Global Positioning System Anti-Jam/Anti-Spoof (GPS AJ), a Degraded Visual Environment (DVE) system, Integrated Vehicle Health
 Monitoring System Control, Video Data Link, Blue Force Tracker 2, Next Gen Crypto Mod Mobile User Objective System (MUOS) including Joint Range Extension Applications Protocol (JREAP), Air Force
 District of Washington (AFDW) mission requirement modifications, Electronic Flight Bags, and Automated Dependent Surveillance Broadcast - In Device. Capability Upgrades and modernization also supports
 inclusion for mandates, hardware and software changes for diminishing manufacturing sources, and component obsolescence issues for aircraft and training systems.

 This requirement (or modification) supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":83,"src_title":"HH60W Modifications","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol II.pdf$$, 613, 613, $$0f201f1c5aee3bf0$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_2035_L187$$, 2027, $$The Games for Training (GFT) Program prepares Soldiers and Leaders by delivering robust training and mission rehearsal capabilities while providing advanced software capabilities to Commercial Off the Shelf
 (COTS) hardware computing systems. The GFT program satisfies the Active, National Guard, and Army Reserves' educational requirements in the Operational, Institutional, and Self-Development Training
 Domains with a low-overhead capability on geo-specific and geo-typical terrain with relevant platforms and weapon systems. This gaming capability allows units and commanders to train individual and collective
 tasks at the company and below level with minimal amount of resourcing required (land, ammunition, transportation, etc.). GFT systems provide commanders the ability to refine and rehearse unit Tactics,
 Techniques, and Procedures (TTPs) and Standard Operating Procedures (SOPs) prior to executing live, large-scale training events. GFT trains units and staffs by facilitating Tactical Exercises Without Troops
 (TEWT).

