INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L114$$, 2027, $$The F-16 is a multi-role fighter that comprises roughly 40% of the USAF fighter fleet with over 810 aircraft supporting a variety of air-to-air and air-to-surface missions, such as offensive and defensive counterair,
 close air support, forward air control, air interdiction (day/night and all-weather), and Suppression of Enemy Air Defenses (SEAD)/Destruction of Enemy Air Defenses (DEAD). F-16 posture and readiness
 combined with low operating costs delivers affordable capacity for the USAF and partner nations. Its capabilities continue to evolve, capitalizing upon advancements made in computers, avionics systems,
 engines, and structural technologies. These advancements meet emerging warfighter requirements to combat current and evolving enemy threats.

 This request will provide funding for F-16 support equipment, facilities support, interim contractor support and production tooling storage management.

 The FY 2026 spend plan amount for Aircraft procurement includes 18,402 thousand of discretionary and 5,200 thousand of mandatory (reconciliation) for a total of 23,602 thousand.

 In FY25, a Congressional Add provided a $50M increase to procure F-16 Simulators for ANG.

 Funding for this exhibit is contained in PE 0207133F$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Air Force                                                                                                                Date: April 2026
