INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L124$$, 2027, $$The Other Production Charges program provides for items which are not directly related to other procurement line items in this appropriation, cannot be reasonably allocated and charged to other procurement
 line items in this appropriation, can be managed as separate end items, may contain certain classified programs, and may be alternate mission equipment, not considered a modification, for out of production
 systems.

 The major efforts supported include funding for Electronic Attack pods and associated test equipment, B-2 Squadrons, F-15E Squadrons, Electronic Warfare (EW) Reprogramming Enterprise and the EW/Cyber
 Combat Assessment via COMBAT SHIELD for multiple combat airframes, F-15 Eagle Passive/Active Warning and Survivability System (EPAWSS), F-16 Squadrons, Combat Training Range Equipment, AN/
 ARC-260 High Frequency Radio Depot activation efforts, Positioning, Navigation, and Timing (PNT) Key Data Loading Installation Facility (KLIF) efforts, T-7A (Advanced Pilot Training) Depot Activation, Aerial
 Targets, Maintenance Support Vehicles or Equipment and the required U.S. contribution for projects defined by the NATO Airborne Early Warning and Control (AEW&C) Board of Directors and approved by the
 U.S. government.

 Funding may be used to address Diminishing Manufacturing Sources (DMS) issues.

