INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3020_L031$$, 2026, $$Program Description: MISSILE REPLENISHMENT SPARES. The Missile Replenishment Spares program funds all ballistic and non-ballistic missile replenishment spares. The replenishment and repair
 spare parts are needed to support and maintain ballistic and non-ballistic missile systems. Replenishment spares include such items as rocket motors, cables, telemetry packages, and electronic components.
 Procurements will include spares with long production lead items.

 The following Major Defense Acquisition Programs (MDAP) have funding in this line:
 AMRAAM, 185
 SDB II, 439
 AIM-9X Blk II, 442

 This program has associated Research Development Test and Evaluation funding in PEs 11120F, 11213F, 27161F, 11122F, and 27163F.$$, NULL, $${"bucket":"fy26_specific_pb_v43_relaxed","method":"placeholder_or_lowscore_li","rapidfuzz_score":0.0,"src_li":31,"src_title":null,"supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196c"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Missile Procurement.pdf$$, 255, 255, $$2000121c9aa8b414$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L002$$, 2027, $$This Budget Line Item (BLI) was consolidated for the FY27 President's Budget (PB). The new BLI, 827000, improves transparency, execution, and long‑term planning.

 The Civil Air Patrol (CAP) is a Congressionally chartered non-profit corporation that serves as the Auxiliary of the Air Force. CAP uses federally provided resources to provide assistance requested by the
 Department of War (DoW), federal, state or local government authorities and non-governmental organizations (NGOs) to perform emergency or non-emergency public purpose missions and activities.

 Pursuant to US Code (Title 10 & 36) the purpose of CAP Corporation is to encourage and aid citizens of the US in contributing their efforts, services, and resources in developing aviation and in maintaining air
 supremacy; and to encourage and develop, by example, the voluntary contribution of private citizens to the public welfare.

 Vehicle procurements enable the Civil Air Patrol (CAP) to provide rapid deployment of emergency essential ground teams who are capable of providing critical communications and humanitarian support during
 national emergencies and disasters.

 CAP's procurement processes/standards are described in Department of Defense Grant & Agreement Regulations.
 Program element associated with this P-1 Line is: 0901223F

 Justification:
 This Budget Line Item (BLI) was consolidated for the FY27 President's Budget (PB). The new BLI, 827000, improves transparency, execution, and long‑term planning.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Air Force                                                                                                                Date: April 2026
